#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
ll dp[N],ans,n,k,d,cnt;
deque<int> dq;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>k;
	dq.push_front(0);
	for(int i=1;i<=n;i++)
	{
		cin>>d;
		cnt+=d;
		if(i>1) dp[i]=dp[dq.front()]+d;
		else dp[i]=d;
//		if(i>1) cout<<dp[i]<<"  = "<<dp[dq.front()]<<" + "<<d<<"\n";
		while(!dq.empty()&&dp[dq.back()]>=dp[i])
		{
//			cout<<dq.size()<<endl;
			dq.pop_back();
		}
		dq.push_back(i);
		while(!dq.empty()&&dq.front()<i-k)
		{
//			cout<<dq.size()<<endl; 
			dq.pop_front();
		}
	}
	for(int i=n-k;i<=n;i++) ans=max(ans,cnt-dp[i]);
	cout<<ans;
	return 0;
}
